   269→// ApplyDiffAndBuild validates and applies a diff, commits changes, and runs a build gate.
   270→func (r *TransflowRunner) ApplyDiffAndBuild(ctx context.Context, repoPath, diffPath string) error {
   271→	// Validate paths first (allowlist)
   272→	allow := []string{"src/**", "pom.xml"}
   273→	if v := os.Getenv("TRANSFLOW_ALLOWLIST"); v != "" {
   274→		allow = strings.Split(v, ",")
   275→	}
   276→	if err := ValidateDiffPaths(diffPath, allow); err != nil {
   277→		return err
   278→	}
   279→	if err := ValidateUnifiedDiff(ctx, repoPath, diffPath); err != nil {
   280→		return err
   281→	}
   282→	if err := ApplyUnifiedDiff(ctx, repoPath, diffPath); err != nil {
   283→		return err
   284→	}
   285→	if err := r.gitOps.CommitChanges(ctx, repoPath, "apply(diff): transflow branch patch"); err != nil {
   286→		return fmt.Errorf("commit failed: %w", err)
   287→	}
   288→	// Build gate
   289→	timeout, err := r.config.ParseBuildTimeout()
   290→	if err != nil {
   291→		return err
   292→	}
   293→	appName := GenerateAppName(r.config.ID)
   294→	buildCfg := common.DeployConfig{
   295→		App:         appName,
   296→		Lane:        r.config.Lane,
   297→		Environment: "dev",
   298→		Timeout:     timeout,
   299→	}
   300→	res, err := r.buildChecker.CheckBuild(ctx, buildCfg)
   301→	if err != nil {
   302→		return fmt.Errorf("build gate failed: %w", err)
   303→	}
   304→	if res != nil && !res.Success {
   305→		return fmt.Errorf("build gate failed: %s", res.Message)
   306→	}
   307→	return nil
   308→}
