    54→
    55→		// Execute ploy arf transform command using full executable path
    56→		cmd := exec.CommandContext(ctx, execPath, args...)
    57→		cmd.Dir = workspacePath
    58→
    59→		if err := cmd.Run(); err != nil {
    60→			return fmt.Errorf("failed to execute recipe %s: %w", recipeID, err)
    61→		}
    62→	}
    63→
    64→	return nil
    65→}
